#include <stdio.h>

int main() {
    int w, h;
    scanf("%d %d", &w, &h);
    int w1, h1;
    scanf("%d %d", &w1, &h1);
    int w2, h2;
    scanf("%d %d", &w2, &h2);
    while (h > 0) {
        w += h;
        if (h == h1) {
            w -= w1;
        }
        if (h == h2) {
            w -= w2;
        }
        h -= 1;
        w = (w > 0) ? w : 0;
    }
    printf("%d\n", w);
    return 0;
}
